			"description": "Color used to fill shape features",
			"type": "string",
			"default": "#606060"
		},
		"mapframe-shape-fill-opacity": {
			"label": "Mapframe shape fill opacity",
			"description": "Opacity level of shape fill, a number between 0 and 1",
			"type": "number",
			"default": "0.5"
		},
		"mapframe-stroke-color": {
